sub 'RemoveTudo' For Each Order EmpCod, ParFiLCod, ParCod Where EmpCod = &EmpCod Where ParCod = &ParCod Delete EndFor
commit EndSub
sub 'UpdateUltimoCodigo' if not &ProgressId.IsEmpty() &Count += 1 If &Count > 0 &Percentual = round((&Count / &Total) * 100, 0) EndIF do 'Atualiza' EndIF
For Each Order EmpCod, ParFiLCod, ParCod Where EmpCod = &EmpCod Where ParCod = &ParCod Where ParFiLCod = &FiLCod ParUltCod = &ParUltCod Exit When none &ParSeq = 0 For Each Order EmpCod, (ParSeq) Where EmpCod = &EmpCod &ParSeq = ParSeq Exit EndFor &ParSeq += 1
new EmpCod = &EmpCod ParSeq = &ParSeq ParCod = &ParCod ParChv = trim(&ParCod.tostring()) ParFiLCod = &FiLCod ParNom = &ParCod.EnumerationDescription() ParUltCod = &ParUltCod EndNEw EndFor
commit EndSub
Sub 'Atualiza'
for each Order ProgressId where ProgressId = &ProgressId ProgressValue = &Percentual When none new ProgressId = &ProgressId ProgressValue = &Percentual Endnew endfor
commit
EndSub
